// Parse Pennsylvania DCED programs page
const items = $input.all();
const grants = [];

for (const item of items) {
  const html = item.json.data || item.json.body || item.json;

  if (typeof html !== 'string') continue;

  // Look for program links in HTML
  const linkPatterns = html.match(/<a[^>]*href="([^"]*program[^"]*)"[^>]*>([^<]+)<\/a>/gi) || [];

  for (const linkHtml of linkPatterns.slice(0, 10)) {
    const hrefMatch = linkHtml.match(/href="([^"]+)"/);
    const textMatch = linkHtml.match(/>([^<]+)</);

    if (!textMatch || !textMatch[1]) continue;

    const title = textMatch[1].trim();
    if (title.length < 5) continue;

    const oppNum = 'PA-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);
    let link = hrefMatch ? hrefMatch[1] : '';
    if (link && !link.startsWith('http')) {
      link = 'https://dced.pa.gov' + (link.startsWith('/') ? '' : '/') + link;
    }

    grants.push({
      json: {
        id: oppNum,
        oppNum: oppNum,
        title: 'Pennsylvania: ' + title,
        description: 'State of Pennsylvania program. Visit PA DCED for eligibility and application details.',
        link: link || 'https://dced.pa.gov/programs-funding/',
        openDate: new Date().toISOString().split('T')[0],
        closeDate: 'See state portal',
        agency: 'PA Dept of Community & Economic Development',
