 const oppNums = items
   .map(item => (item.json.oppNum || '').trim())
   .filter(id => id.length > 0);

 const existingOppNums = new Set();

 for (let i = 0; i < oppNums.length; i += 500) {
   const chunk = oppNums.slice(i, i + 500);
   const filter = chunk.map(id => `"${id}"`).join(',');

   try {
     const response = await this.helpers.httpRequest({
       method: 'GET',
       url: `${supabaseUrl}?source_id=in.(${filter})&organization_id=eq.${orgId}&select=source_id`,
       headers: {
         'apikey': supabaseKey,
         'Authorization': 'Bearer ' + supabaseKey,
       },
     });

     if (Array.isArray(response)) {
       response.forEach(r => existingOppNums.add(r.source_id));
     }
   } catch (e) {
     // If batch check fails, continue
   }
 }

 for (const item of items) {
   const grant = item.json;
   const oppNum = (grant.oppNum || '').trim();

   if (!oppNum || existingOppNums.has(oppNum)) continue;

   results.push({
     json: {
       grant,
       hasGrants: true,
       status: 'new',
       message: 'Grant not found in Supabase, will be added',
     },
   });
 }

 if (results.length === 0) {
   return [{ json: { hasGrants: false, noNewGrants: true, message: 'All grants already tracked' } }];
 }

 return results;

